package deps

import (
	"strings"
	"testing"
)

func TestParseLockFile(t *testing.T) {
	input := `
# Auto-generated by yar. Do not edit.

[[package]]
name = "http"
git = "https://github.com/user/yar-http.git"
tag = "v0.3.1"
commit = "abc123def456789012345678901234567890abcd"
hash = "sha256:9f86d081884c7d659a2feaa0c55ad015a3bf4f1b2b0b822cd15d6c15b0f00a08"

[[package]]
name = "json"
git = "https://github.com/user/yar-json.git"
rev = "def789"
commit = "def789abc123456012345678901234567890abcd"
hash = "sha256:1234567890abcdef1234567890abcdef1234567890abcdef1234567890abcdef"
`
	entries, err := ParseLockFile(input)
	if err != nil {
		t.Fatalf("ParseLockFile: %v", err)
	}
	if len(entries) != 2 {
		t.Fatalf("len(entries) = %d, want 2", len(entries))
	}
	if entries[0].Name != "http" {
		t.Errorf("entries[0].Name = %q", entries[0].Name)
	}
	if entries[0].Tag != "v0.3.1" {
		t.Errorf("entries[0].Tag = %q", entries[0].Tag)
	}
	if entries[0].Commit != "abc123def456789012345678901234567890abcd" {
		t.Errorf("entries[0].Commit = %q", entries[0].Commit)
	}
	if entries[1].Rev != "def789" {
		t.Errorf("entries[1].Rev = %q", entries[1].Rev)
	}
}

func TestParseLockFileMissingFields(t *testing.T) {
	tests := []struct {
		name  string
		input string
	}{
		{
			"missing name",
			`[[package]]
git = "https://example.com/repo.git"
commit = "abc123"
hash = "sha256:abc"`,
		},
		{
			"missing git",
			`[[package]]
name = "lib"
commit = "abc123"
hash = "sha256:abc"`,
		},
		{
			"missing commit",
			`[[package]]
name = "lib"
git = "https://example.com/repo.git"
hash = "sha256:abc"`,
		},
		{
			"missing hash",
			`[[package]]
name = "lib"
git = "https://example.com/repo.git"
commit = "abc123"`,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := ParseLockFile(tt.input)
			if err == nil {
				t.Fatalf("expected error for %s", tt.name)
			}
		})
	}
}

func TestWriteLockFile(t *testing.T) {
	entries := []LockEntry{
		{
			Name:   "json",
			Git:    "https://github.com/user/yar-json.git",
			Rev:    "def789",
			Commit: "def789abc123456012345678901234567890abcd",
			Hash:   "sha256:1234",
		},
		{
			Name:   "http",
			Git:    "https://github.com/user/yar-http.git",
			Tag:    "v0.3.1",
			Commit: "abc123def456789012345678901234567890abcd",
			Hash:   "sha256:5678",
		},
	}
	out := WriteLockFile(entries)

	// Should be sorted by name.
	httpIdx := strings.Index(out, `name = "http"`)
	jsonIdx := strings.Index(out, `name = "json"`)
	if httpIdx < 0 || jsonIdx < 0 {
		t.Fatalf("missing entries in output:\n%s", out)
	}
	if httpIdx > jsonIdx {
		t.Error("entries not sorted by name")
	}

	// Should contain the header.
	if !strings.HasPrefix(out, "# Auto-generated") {
		t.Error("missing header comment")
	}

	// Round-trip.
	parsed, err := ParseLockFile(out)
	if err != nil {
		t.Fatalf("round-trip ParseLockFile: %v", err)
	}
	if len(parsed) != 2 {
		t.Fatalf("round-trip len = %d", len(parsed))
	}
	if parsed[0].Name != "http" {
		t.Errorf("round-trip first entry = %q, want http", parsed[0].Name)
	}
}

func TestLockIndex(t *testing.T) {
	entries := []LockEntry{
		{Name: "http", Git: "https://example.com/http.git", Commit: "abc", Hash: "sha256:1"},
		{Name: "json", Git: "https://example.com/json.git", Commit: "def", Hash: "sha256:2"},
	}
	idx := LockIndex(entries)
	if idx["http"].Commit != "abc" {
		t.Errorf("http commit = %q", idx["http"].Commit)
	}
	if idx["json"].Commit != "def" {
		t.Errorf("json commit = %q", idx["json"].Commit)
	}
	if idx["missing"] != nil {
		t.Error("expected nil for missing key")
	}
}
